"""Graph 节点：汇总已执行评估 Agent 的分数，计算 total_score。"""

from __future__ import annotations

from state import (
    LearningState,
    ROUTE_LABELS,
    ScoreDetail,
    ScoringNodeUpdate,
    get_active_routes,
)

ROUTE_RESULT_KEY: dict[str, str] = {
    "theory": "theory_result",
    "practice": "practice_result",
    "data": "data_result",
    "literature": "literature_result",
}


def _read_score(result: object) -> float | None:
    if not isinstance(result, dict):
        return None
    raw = result.get("score")
    if raw is None:
        return None
    try:
        return float(max(0.0, min(100.0, round(float(raw), 2))))
    except (TypeError, ValueError):
        return None


def collect_route_scores(state: LearningState) -> ScoreDetail:
    """仅统计当前路由实际执行的 Agent 分数。"""
    routes = get_active_routes(state)
    items: list[dict[str, object]] = []
    scores: dict[str, float] = {}

    for route in routes:
        result_key = ROUTE_RESULT_KEY.get(route)
        if not result_key:
            continue
        score = _read_score(state.get(result_key))
        if score is None:
            continue
        label = ROUTE_LABELS.get(route, route)
        items.append({"route": route, "label": label, "score": score})
        scores[route] = score

    count = len(items)
    average = round(sum(scores.values()) / count, 2) if count else 0.0

    return {
        "routes": routes,
        "items": items,
        "scores": scores,
        "count": count,
        "average": average,
    }


def compute_total_score(score_detail: ScoreDetail) -> float:
    """total_score 为已执行 Agent 分数的算术平均（单路由时即该 Agent 分数）。"""
    return float(score_detail.get("average") or 0.0)


def scoring_node(state: LearningState) -> ScoringNodeUpdate:
    score_detail = collect_route_scores(state)
    total_score = compute_total_score(score_detail)
    return {
        "total_score": total_score,
        "score_detail": score_detail,
    }


__all__ = [
    "ROUTE_RESULT_KEY",
    "collect_route_scores",
    "compute_total_score",
    "scoring_node",
]

"""Graph 节点：按 session_id 加载会话历史，写入 chat_history。"""

from __future__ import annotations

from memory.session_manager import SessionManager
from state import HistoryTurn, LearningState


class LoadMemoryNodeUpdate(TypedDict, total=False):
    chat_history: list[HistoryTurn]


def _messages_to_chat_history(messages: list[dict]) -> list[HistoryTurn]:
    """将会话消息转为 state.chat_history 条目。"""
    history: list[HistoryTurn] = []
    for index, message in enumerate(messages, start=1):
        role = str(message.get("role") or "").strip()
        content = str(message.get("content") or "").strip()
        if not role or not content:
            continue
        turn: HistoryTurn = {"role": role, "content": content}
        message_id = str(message.get("message_id") or "").strip()
        if message_id:
            turn["turn_id"] = index
        history.append(turn)
    return history


def load_session_chat_history(
    session_id: str,
    *,
    limit: int | None = None,
) -> list[HistoryTurn]:
    """不经过图，直接按 session_id 加载 chat_history。"""
    session_id = (session_id or "").strip()
    if not session_id:
        return []

    try:
        manager = SessionManager(session_id)
        messages = manager.load_history(limit=limit)
    except (ValueError, FileNotFoundError):
        return []

    return _messages_to_chat_history(messages)


def load_memory_node(state: LearningState) -> LoadMemoryNodeUpdate:
    """
    根据 state.session_id 读取会话历史消息，写入 chat_history。

    无 session_id 或会话不存在时返回空列表。
    """
    session_id = (state.get("session_id") or "").strip()
    if not session_id:
        return {"chat_history": []}

    chat_history = load_session_chat_history(session_id)
    return {"chat_history": chat_history}


