    limit: int = 100,
) -> list[dict[str, Any]]:
    """列出所有会话摘要，按 updated_at 降序。"""
    base = sessions_dir or DEFAULT_SESSIONS_DIR
    if not base.is_dir():
        return []

    items: list[dict[str, Any]] = []
    for path in base.glob("*.json"):
        try:
